ety-Nine Ōji|4=fr|5=Kujūkuōji|1=Ninety-Nine Ōji|lt=Ninety-Nine Ōji|1=List of Ninety-Nine Ōji (Kaizuka)|en|lt=List of Ninety-Nine Ōji (Kaizuka)|lt=Kuramochi Ōji|error=九十九王子 (岸和田市・貝塚市)|oji=王子|qq=draft|12=simple|13=User:Immanuelle/List of Ninety-Nine Ōji (Kaizuka)|13=User:Immanuelle/Ninety-Nine Ōji|lt=Ninety-Nine Ōji|qq=}}''' → {{ill|List of Ninety-Nine Ōji (Izumisano City)|ja|九十九王子|lt=Ninety-Nine Ōji|1=Ninety-Nine Ōji|lt=Ninety-Nine Ōji|2=ja|3=九十九王子|lt=Ninety-Nine Ōji|4=fr|5=Kujūkuōji|1=Ninety-Nine Ōji|lt=Ninety-Nine Ōji|1=List of Ninety-Nine Ōji (Kaizuka)|en|lt=Tsuruhara Ōji|error=九十九王子 (岸和田市・貝塚市)|oji=王子|qq=draft|12=simple|13=User:Immanuelle/List of Ninety-Nine Ōji (Izumisano City)|13=User:Immanuelle/Ninety-Nine Ōji|lt=Ninety-Nine Ōji|qq=}}'''
